python3 -c "
import json,re,collections
recs=[json.loads(l) for l in open('gpt55_board/cellcog-max.jsonl')]
P={
 'Thread refs [ALLCAPS-ID]':r'\[[A-Z][A-Z0-9\-]{4,40}\]',
 'named phases (Phase Nx / Plan N / Sweep)':r'Phase \d+[a-z]?|Plan [12]\b|Scout Sweep|Sweep \d',
 'invented scoring model/rubric':r'\d+\s*分制|评分模型|评估模型|scoring (?:model|rubric|framework)|weighted score|\d+-point (?:scale|rubric)|梯队',
 'counter-argument para 反方':r'反方|反驳|反面证据|Counter-?(?:argument|evidence|case)|steelman|Devil.s advocate|可能使该洞察不成立',
 'CONFIRMED/REFINED/INVALIDATED verdicts':r'CONFIRMED|INVALIDATED|REFINED|PARTIALLY CONFIRMED|证伪|被推翻',
}
hit=collections.defaultdict(set); cnt=collections.Counter()
for r in recs:
    for k,p in P.items():
        m=re.findall(p,r['article'])
        if m: hit[k].add(r['id']); cnt[k]+=len(m)
for k in P: print(f'{k:44} {len(hit[k]):3}/100 reports  ({cnt[k]} hits)')
print()
th=collections.Counter()
for r in recs:
    for m in re.findall(r'\[([A-Z][A-Z0-9\-]{4,40})\]',r['article']): th[m]+=1
print('sample Thread IDs:',[k for k,v in th.most_common(25)])
"
